// generated by Claude Free

 #define p_cubNvgeo  12
void reference(
    const int     Nelements,
    const dfloat* vgeo,
    const dfloat* cubvgeo,
    const dfloat* cubD,
    const dfloat* cubInterpT,
    const int     offset,
    const dfloat* U,
    dfloat*       NU)
{
    // Temporaries for one element — reused across elements
    const int cNp  = p_cubNp;
    const int cQ   = p_cubNq;
    const int cQ2  = p_cubNq * p_cubNq;
    const int Nq   = p_Nq;
    const int Nq2  = p_Nq * p_Nq;

    // Cubature-resolution interpolated velocity fields
    dfloat* cU = (dfloat*)malloc(cNp * sizeof(dfloat));
    dfloat* cV = (dfloat*)malloc(cNp * sizeof(dfloat));
    dfloat* cW = (dfloat*)malloc(cNp * sizeof(dfloat));

    // Advective flux divergence at cubature nodes (overwritten in Phase 2)
    dfloat* rU = (dfloat*)malloc(cNp * sizeof(dfloat));
    dfloat* rV = (dfloat*)malloc(cNp * sizeof(dfloat));
    dfloat* rW = (dfloat*)malloc(cNp * sizeof(dfloat));

    // Phase 1 intermediates: largest stage is [p_cubNq][p_cubNq][p_cubNq]
    int tmpSz = p_cubNq * p_cubNq * p_cubNq;
    dfloat* tmp1 = (dfloat*)malloc(tmpSz * sizeof(dfloat));
    dfloat* tmp2 = (dfloat*)malloc(tmpSz * sizeof(dfloat));

    for (int e = 0; e < Nelements; e++) {

        // =============================================================
        // PHASE 1: Interpolate (U,V,W) from 8^3 → 16^3
        //
        // The velocity field always has 3 components stored at:
        //   U[0*offset .. 1*offset-1]  (u)
        //   U[1*offset .. 2*offset-1]  (v)
        //   U[2*offset .. 3*offset-1]  (w)
        // so U must be allocated as 3*offset elements.
        //
        // cubInterpT layout: [p_Nq][p_cubNq]  row=solution node, col=cub node
        //   cubInterpT[a][i] = cubInterpT[a*p_cubNq + i]
        //
        // CUDA kernel breakdown (for U, same for V and W):
        //   r-sweep (j<8, i<16):
        //     s_U1[j][i] = sum_{a=0}^{7} cubInterpT[a][i] * s_U[j][a]
        //   s-sweep (j<16, i<16):
        //     U2 = sum_{b=0}^{7} cubInterpT[b][j] * s_U1[b][i]
        //   t-accumulation over c=0..7:
        //     r_U[k] += cubInterpT[c][k] * U2
        // =============================================================
        for (int field = 0; field < 3; field++) {
            const dfloat* Uf = U + field * offset + e * p_Np;
            dfloat*       cf = (field==0) ? cU : (field==1) ? cV : cW;

            // r-sweep: [t_sol=c][s_sol=j][r_cub=i]
            //   tmp1[c][j][i] = sum_a cubInterpT[a][i] * Uf[c][j][a]
            for (int c = 0; c < Nq; c++)
            for (int j = 0; j < Nq; j++)
            for (int i = 0; i < cQ; i++) {
                dfloat val = 0;
                for (int a = 0; a < Nq; a++)
                    val += cubInterpT[a*cQ + i] * Uf[c*Nq2 + j*Nq + a];
                tmp1[c*Nq*cQ + j*cQ + i] = val;
            }

            // s-sweep: [t_sol=c][s_cub=j][r_cub=i]
            //   tmp2[c][j][i] = sum_b cubInterpT[b][j] * tmp1[c][b][i]
            for (int c = 0; c < Nq; c++)
            for (int j = 0; j < cQ; j++)
            for (int i = 0; i < cQ; i++) {
                dfloat val = 0;
                for (int b = 0; b < Nq; b++)
                    val += cubInterpT[b*cQ + j] * tmp1[c*Nq*cQ + b*cQ + i];
                tmp2[c*cQ2 + j*cQ + i] = val;
            }

            // t-sweep: [t_cub=k][s_cub=j][r_cub=i]
            //   cf[k][j][i] = sum_c cubInterpT[c][k] * tmp2[c][j][i]
            for (int k = 0; k < cQ; k++)
            for (int j = 0; j < cQ; j++)
            for (int i = 0; i < cQ; i++) {
                dfloat val = 0;
                for (int c = 0; c < Nq; c++)
                    val += cubInterpT[c*cQ + k] * tmp2[c*cQ2 + j*cQ + i];
                cf[k*cQ2 + j*cQ + i] = val;
            }
        }

        // =============================================================
        // PHASE 2: Advective flux divergence at each cubature node (i,j,k)
        //
        // Reference derivatives using cubD [p_cubNq][p_cubNq]:
        //   dU/dr[k][j][i] = sum_n cubD[i][n] * cU[k][j][n]
        //   dU/ds[k][j][i] = sum_n cubD[j][n] * cU[k][n][i]
        //   dU/dt[k][j][i] = sum_n cubD[k][n] * cU[n][j][i]
        //
        // Contravariant fluxes (JW-weighted):
        //   Uhat = JW*(U*drdx + V*drdy + W*drdz)   (r-direction)
        //   Vhat = JW*(U*dsdx + V*dsdy + W*dsdz)   (s-direction)
        //   What = JW*(U*dtdx + V*dtdy + W*dtdz)   (t-direction)
        //
        // Strong-form flux divergence:
        //   rU[k][j][i] = Uhat*dU/dr + Vhat*dU/ds + What*dU/dt
        //
        // cubvgeo layout: [e*p_cubNp*p_cubNvgeo + field*p_cubNp + k*cQ2+j*cQ+i]
        //   matching CUDA: gid = e*p_cubNp*p_Nvgeo + k*16*16 + j*16 + i
        // =============================================================
        for (int k = 0; k < cQ; k++)
        for (int j = 0; j < cQ; j++)
        for (int i = 0; i < cQ; i++) {

            // r-derivatives
            dfloat Udr=0, Vdr=0, Wdr=0;
            for (int n = 0; n < cQ; n++) {
                dfloat Din = cubD[i*cQ + n];
                Udr += Din * cU[k*cQ2 + j*cQ + n];
                Vdr += Din * cV[k*cQ2 + j*cQ + n];
                Wdr += Din * cW[k*cQ2 + j*cQ + n];
            }

            // s-derivatives
            dfloat Uds=0, Vds=0, Wds=0;
            for (int n = 0; n < cQ; n++) {
                dfloat Djn = cubD[j*cQ + n];
                Uds += Djn * cU[k*cQ2 + n*cQ + i];
                Vds += Djn * cV[k*cQ2 + n*cQ + i];
                Wds += Djn * cW[k*cQ2 + n*cQ + i];
            }

            // t-derivatives
            dfloat Udt=0, Vdt=0, Wdt=0;
            for (int n = 0; n < cQ; n++) {
                dfloat Dkn = cubD[k*cQ + n];
                Udt += Dkn * cU[n*cQ2 + j*cQ + i];
                Vdt += Dkn * cV[n*cQ2 + j*cQ + i];
                Wdt += Dkn * cW[n*cQ2 + j*cQ + i];
            }

            // Geometry: gid = e*p_cubNp*p_cubNvgeo + k*cQ2 + j*cQ + i
            const int gid = e * p_cubNp * p_cubNvgeo + k*cQ2 + j*cQ + i;
            const dfloat drdx = cubvgeo[gid + p_RXID*p_cubNp];
            const dfloat drdy = cubvgeo[gid + p_RYID*p_cubNp];
            const dfloat drdz = cubvgeo[gid + p_RZID*p_cubNp];
            const dfloat dsdx = cubvgeo[gid + p_SXID*p_cubNp];
            const dfloat dsdy = cubvgeo[gid + p_SYID*p_cubNp];
            const dfloat dsdz = cubvgeo[gid + p_SZID*p_cubNp];
            const dfloat dtdx = cubvgeo[gid + p_TXID*p_cubNp];
            const dfloat dtdy = cubvgeo[gid + p_TYID*p_cubNp];
            const dfloat dtdz = cubvgeo[gid + p_TZID*p_cubNp];
            const dfloat JW   = cubvgeo[gid + p_JWID*p_cubNp];

            const dfloat Un = cU[k*cQ2 + j*cQ + i];
            const dfloat Vn = cV[k*cQ2 + j*cQ + i];
            const dfloat Wn = cW[k*cQ2 + j*cQ + i];

            // Contravariant fluxes (JW-weighted)
            const dfloat Uhat = JW*(Un*drdx + Vn*drdy + Wn*drdz);
            const dfloat Vhat = JW*(Un*dsdx + Vn*dsdy + Wn*dsdz);
            const dfloat What = JW*(Un*dtdx + Vn*dtdy + Wn*dtdz);

            // Strong-form advective flux divergence
            const int cidx = k*cQ2 + j*cQ + i;
            rU[cidx] = Uhat*Udr + Vhat*Uds + What*Udt;
            rV[cidx] = Uhat*Vdr + Vhat*Vds + What*Vdt;   // Bug fix: was What*Wdt
            rW[cidx] = Uhat*Wdr + Vhat*Wds + What*Wdt;
        }

        // =============================================================
        // PHASE 3: Project (rU,rV,rW) from 16^3 cubature → 8^3 solution
        //          nodes via cubInterpT, then scale by IJW.
        //
        // Exact translation of CUDA Phase 3 (the c-loop).
        // Three steps per sol-t node c:
        //
        // T-STEP:  rhsU = sum_{k=0}^{15} cubInterpT[c][k] * r_U[k]
        //   CUDA stores into s_U[j][i] only for i<8 && j<8.
        //   → Only the (cub_s=0..7, cub_r=0..7) corner is retained.
        //   → t_proj[j][i] = sum_k cubInterpT[c*cQ+k] * rU[k*cQ2+j*cQ+i]
        //     for j=0..7, i=0..7 only.
        //
        // S-STEP:  (CUDA: j<8 threads; guard k<8 && i<8 inside loop)
        //   rhsU = sum_{k=0}^{7} cubInterpT[j_sol][k] * t_proj[k][i]
        //   → s_U1[j][i] nonzero only for j<8, i<8 (i>=8 guard zeros those).
        //   → s_proj[j][i] for j=0..7, i=0..7.
        //
        // R-STEP:  (CUDA: i<8 && j<8 threads; sums k=0..15 but s_U1[j][k]=0 for k>=8)
        //   rhsU = sum_{k=0}^{7} cubInterpT[i_sol][k] * s_proj[j][k]
        //   → write NU scaled by IJW.
        //
        // CUDA geometry read: gid = e*p_Np*p_Nvgeo + c*64 + j*8 + i
        // CUDA NU write:      id  = e*p_Np          + c*64 + j*8 + i
        // =============================================================

        // Fixed-size 8×8 intermediates (matching CUDA s_U[8][8] and s_U1[8][8] corner)
        dfloat t_projU[8][8], t_projV[8][8], t_projW[8][8];
        dfloat s_projU[8][8], s_projV[8][8], s_projW[8][8];

        for (int c = 0; c < Nq; c++) {

            // -- T-step: project cub-t (k=0..15) → sol-t node c
            //    Only for j=0..7, i=0..7  (matching CUDA "if i<8 && j<8")
            for (int j = 0; j < 8; j++)
            for (int i = 0; i < 8; i++) {
                dfloat vU=0, vV=0, vW=0;
                for (int k = 0; k < cQ; k++) {
                    dfloat Ikc = cubInterpT[c*cQ + k];
                    vU += Ikc * rU[k*cQ2 + j*cQ + i];
                    vV += Ikc * rV[k*cQ2 + j*cQ + i];
                    vW += Ikc * rW[k*cQ2 + j*cQ + i];
                }
                t_projU[j][i] = vU;
                t_projV[j][i] = vV;
                t_projW[j][i] = vW;
            }

            // -- S-step: project cub-s → sol-s node j
            //    CUDA guard: k<8 && i<8 — only k=0..7 and i=0..7
            //    s_U1[j][i] = 0 for i>=8 (guard prevents writes), so only store 8×8
            for (int j = 0; j < Nq; j++)
            for (int i = 0; i < 8; i++) {
                dfloat vU=0, vV=0, vW=0;
                for (int k = 0; k < 8; k++) {    // k<8 guard from CUDA
                    dfloat Ijb = cubInterpT[j*cQ + k];
                    vU += Ijb * t_projU[k][i];
                    vV += Ijb * t_projV[k][i];
                    vW += Ijb * t_projW[k][i];
                }
                s_projU[j][i] = vU;
                s_projV[j][i] = vV;
                s_projW[j][i] = vW;
            }

            // -- R-step: project cub-r → sol-r node i
            //    CUDA sums k=0..15 but s_U1[j][k]=0 for k>=8, so effectively k=0..7
            for (int j = 0; j < Nq; j++)
            for (int i = 0; i < Nq; i++) {
                dfloat vU=0, vV=0, vW=0;
                for (int k = 0; k < 8; k++) {    // s_proj only nonzero for k<8
                    dfloat Iia = cubInterpT[i*cQ + k];
                    vU += Iia * s_projU[j][k];
                    vV += Iia * s_projV[j][k];
                    vW += Iia * s_projW[j][k];
                }

                // Geometry: IJW from vgeo
                // CUDA: gid = e*p_Np*p_Nvgeo + c*8*8 + j*8 + i
                const int gid = e*p_Np*p_Nvgeo + c*Nq2 + j*Nq + i;
                const dfloat IJW = vgeo[gid + p_IJWID*p_Np];

                // CUDA: id = e*p_Np + c*64 + j*8 + i
                const int id = e*p_Np + c*Nq2 + j*Nq + i;
                NU[id + 0*offset] = IJW * vU;
                NU[id + 1*offset] = IJW * vV;
                NU[id + 2*offset] = IJW * vW;
            }
        }

    } // element loop

    free(cU); free(cV); free(cW);
    free(rU); free(rV); free(rW);
}

